import{_ as a,r as o,o as r,c as l,a as n,b as t,d as p,w as h,e as s}from"./chunks/framework.8tiMeCK-.js";const v=JSON.parse('{"title":"7.6  Capturing Crash Logs in Interrupt Context Using a Console Device","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_debugging/ch07_6.md","filePath":"en/notes/linux_kernel_debugging/ch07_6.md","lastUpdated":null}'),d={name:"en/notes/linux_kernel_debugging/ch07_6.md"};function c(u,e,g,k,m,b){const i=o("IRQ");return r(),l("div",null,[e[5]||(e[5]=n(`<h1 id="_7-6-capturing-crash-logs-in-interrupt-context-using-a-console-device" tabindex="-1">7.6 Capturing Crash Logs in Interrupt Context Using a Console Device <a class="header-anchor" href="#_7-6-capturing-crash-logs-in-interrupt-context-using-a-console-device" aria-label="Permalink to &quot;7.6  Capturing Crash Logs in Interrupt Context Using a Console Device&quot;">​</a></h1><p>In the previous section, we added a few more sharp tools to our toolbox—ranging from stack space checks to source code locating scripts. You might think that with these, even if the kernel crashes, we can pin it down effortlessly.</p><p>Don&#39;t be too confident.</p><p>Our previous test environment had a bit of a &quot;greenhouse&quot; feel: whether triggered directly or via a workqueue, our Oops always occurred in <strong>process context</strong>. What does that mean? It means the kernel still had a chance to &quot;gracefully&quot; report the error, print the stack trace to the screen, and might even let you type a few more commands.</p><p>But in the real world, many tricky crashes happen in a much more dangerous place—<strong>interrupt context</strong>.</p><p>There&#39;s no process to blame, no way out, and—if you&#39;re unlucky—even the screen output gets swallowed.</p><p>In this section, we&#39;re going to push the scenario to the extreme: we&#39;ll manually trigger a crash inside a hard interrupt handler, and then see how we can retrieve that life-saving diagnostic log when the system freezes, the keyboard becomes unresponsive, and even <code>SysRq</code> commands can&#39;t be typed.</p><hr><h3 id="a-runaway-interrupt-context" tabindex="-1">A Runaway Interrupt Context <a class="header-anchor" href="#a-runaway-interrupt-context" aria-label="Permalink to &quot;A Runaway Interrupt Context&quot;">​</a></h3><p>We&#39;ve prepared a new test module <code>irq_crash.ko</code>. Its logic is simple and brutal: it uses the kernel&#39;s <code>tasklet</code> mechanism to register a function for execution in interrupt context.</p><p>Let&#39;s briefly review this (we used a similar technique in the memory leak test in the previous chapter): <code>tasklet</code> is a special asynchronous execution mechanism that guarantees the callback function will be executed in interrupt context (usually a hardirq).</p><p>Let&#39;s look at the code:</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ch7/oops_inirqv3/oops_inirqv3.c</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> irq_work</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> irq_work </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">irqwk</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> want_oops </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PRINT_CTX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 打印当前上下文信息，让我们确信它在 IRQ 里</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">want_oops)</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // 好了，让我们在中断里制造个事故</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // 这一行可能导致致命死锁！</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;x&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Notice that comment. We manually write data to the <code>0x10</code> address. This is obviously an illegal operation (located within the NULL trap page) and will trigger a page fault.</p><p>Now, load this module in your virtual machine:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch7/oops_inirqv3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> insmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_inirqv3.ko</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>In my test environment (VirtualBox 6.1 + Ubuntu 20.04 Guest + 5.10.60 kernel), after pressing Enter, something despairing happened:</p><p><strong>Nothing happened.</strong></p><p>It wasn&#39;t a &quot;printed a bunch of errors and then froze&quot; kind of nothing. The screen simply went black, or the cursor completely stopped moving. No Oops information, no <code>SysRq</code> prompt, not even the Caps Lock light blinked.</p><p>The system just died right in front of you.</p><p>What now? <code>SysRq</code>? Can&#39;t type it. Reboot? Logs are all gone.</p><p>At this point, as an engineer, your intuition will tell you: <strong>The kernel definitely wanted to speak, but its words couldn&#39;t reach the display.</strong> We need another channel—a channel that doesn&#39;t rely on the GPU driver—to smuggle out the kernel&#39;s dying words.</p><hr><h3 id="taking-a-detour-the-virtual-serial-console" tabindex="-1">Taking a Detour: The Virtual Serial Console <a class="header-anchor" href="#taking-a-detour-the-virtual-serial-console" aria-label="Permalink to &quot;Taking a Detour: The Virtual Serial Console&quot;">​</a></h3><p>Welcome to the real world.</p><p>The approach to solving this problem is a classic one. Although our operations here target a virtualized environment like VirtualBox, the underlying concept applies to almost all embedded development boards and servers:</p><blockquote><p><strong>Since the graphical interface (display) route is broken, we&#39;ll use the serial port route to &quot;smuggle&quot; the logs out.</strong></p></blockquote><p>What we need to do is establish a &quot;virtual cable&quot; between the guest and the host—a virtual serial port. The kernel will write all <code>printk</code> information to this serial port simultaneously, and the other end of the serial port will be connected to a plain text file on your host machine.</p><h4 id="step-1-configure-the-virtual-serial-port-on-the-host" tabindex="-1">Step 1: Configure the Virtual Serial Port on the Host <a class="header-anchor" href="#step-1-configure-the-virtual-serial-port-on-the-host" aria-label="Permalink to &quot;Step 1: Configure the Virtual Serial Port on the Host&quot;">​</a></h4><p>If the virtual machine is still running, shut it down first.</p><p>Open the Oracle VirtualBox manager interface, select your virtual machine, and click the &quot;Settings&quot; gear icon.</p><ol><li>Find <strong>&quot;Serial Ports&quot;</strong> in the left menu.</li><li>Check <strong>&quot;Enable Port 1&quot;</strong>.</li><li><strong>Port Mode</strong>: Select <strong>&quot;Raw File&quot;</strong>. This means data will be written directly to a file, rather than to another network stream or physical device.</li><li><strong>Path/Address</strong>: Enter a file path on your host machine. For example, on my Linux host, I entered <code>~/vb_serial.log</code>.</li></ol><p>The configuration should look something like this (see Figure 7.21 in the book). Click OK to save.</p><h4 id="step-2-tell-the-kernel-to-use-this-console" tabindex="-1">Step 2: Tell the Kernel to Use This Console <a class="header-anchor" href="#step-2-tell-the-kernel-to-use-this-console" aria-label="Permalink to &quot;Step 2: Tell the Kernel to Use This Console&quot;">​</a></h4><p>Now start the virtual machine. But before the kernel actually boots, we need to hijack the boot parameters.</p><ol><li>Mash the <code>Esc</code> key during boot to interrupt the GRUB boot process and enter the menu.</li><li>Find <strong>&quot;Advanced options for Ubuntu&quot;</strong> and select the custom kernel we want to test (5.10.60-prod01) inside it.</li><li>Press the <code>e</code> key to edit the boot entry.</li><li>Find the line starting with <code>linux</code>.</li></ol><p>This is where we make our move. Move the cursor to the end of this line and append this string of parameters:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>console=ttyS0 console=tty0 ignore_loglevel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Here, <code>ttyS0</code> is our serial port device. <code>console=ttyS0</code> tells the kernel to &quot;redirect console output to the serial port,&quot; while <code>console=tty0</code> retains the screen output. <code>loglevel=8</code> is the old saying: &quot;spit everything out, don&#39;t worry about log levels, I want it all.&quot;</p><p>After making the changes, press <code>Ctrl+x</code> to boot the system.</p><hr><h3 id="verifying-the-channel-and-capturing-the-crash" tabindex="-1">Verifying the Channel and Capturing the Crash <a class="header-anchor" href="#verifying-the-channel-and-capturing-the-crash" aria-label="Permalink to &quot;Verifying the Channel and Capturing the Crash&quot;">​</a></h3><p>After entering the system, don&#39;t rush to load the module. We need to confirm that this &quot;smuggling channel&quot; is open first.</p><p><strong>Verifying Serial Output</strong></p><p>Inside the virtual machine, execute this command as root:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># echo &quot;testing serial console 1 2 3&quot; &gt; /dev/kmsg</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>At this moment, something magical happens.</p><p>Switch to your host machine and open the log file you just specified (e.g., <code>~/vb_serial.log</code>). You should see the line you just typed already sitting in there:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ tail -n1 ~/console_lkd.txt</span></span>
<span class="line"><span>[  646.403129] testing serial console 1 2 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The channel is open. Now, even if there&#39;s an abyss ahead, we have a safety rope.</p><p><strong>Triggering the Crash Again</strong></p><p>Go back to the virtual machine and load that ruthless module again:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch7/oops_inirqv3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> insmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_inirqv3.ko</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>As expected, the virtual machine instantly freezes, and the interface locks up.</p><p>Ignore it. Go back to the host machine and open that log file.</p><blockquote><p><strong>Victory Moment</strong></p><p>Although the virtual machine&#39;s screen is dead and pitch-black, inside the text file on the host, the kernel has clearly stated everything it wanted to say (see Figure 7.23 in the book).</p></blockquote><p>You will see the complete Oops stack trace, clear enough to bring a tear to your eye.</p><hr><h3 id="in-depth-diagnostics-the-stack-fingerprint-of-interrupt-context" tabindex="-1">In-Depth Diagnostics: The Stack Fingerprint of Interrupt Context <a class="header-anchor" href="#in-depth-diagnostics-the-stack-fingerprint-of-interrupt-context" aria-label="Permalink to &quot;In-Depth Diagnostics: The Stack Fingerprint of Interrupt Context&quot;">​</a></h3><p>Getting the log is only the first step; now comes the detective work.</p><p>Look closely at this Oops output. It has a few very critical differences compared to the crashes we triggered in process context before.</p><p><strong>1. The Direction of the RIP Pointer</strong></p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RIP: 0010:irq_work+0x18/0x20 [oops_inirqv3]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The RIP points directly to our <code>irq_crash_tasklet_func</code> function. This confirms that the crash indeed occurred inside our designated interrupt callback.</p><p><strong>2. The Dual Stack</strong></p><p>This is the most fascinating part. You&#39;ll notice that this Call Trace is split into two sections, with a clear marker in between:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;IRQ&gt;</span></span>
<span class="line"><span>irq_work+0x18/0x20 [oops_inirqv3]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>&lt;/IRQ&gt;</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>On modern architectures like x86_64, interrupt handling uses a dedicated <strong>interrupt stack</strong>.</p>`,68)),t("ul",null,[t("li",null,[t("strong",null,[p(i,null,{default:h(()=>[...e[0]||(e[0]=[s(" ... ",-1)])]),_:1})]),e[1]||(e[1]=s(": This region records the execution path when the interrupt occurred. It starts from the interrupt entry point, which is where ",-1)),e[2]||(e[2]=t("code",null,"irq_crash_tasklet_func",-1)),e[3]||(e[3]=s(" resides.",-1))]),e[4]||(e[4]=t("li",null,[t("strong",null,"The lower section"),s(": This is the original stack of the process that was interrupted.")],-1))]),e[6]||(e[6]=n('<p>Reading this stack <strong>bottom-up</strong>, you&#39;ll find that the kernel was originally executing some process&#39;s task (perhaps <code>bash</code>, or maybe the idle thread), when it was suddenly interrupted, switched to the interrupt stack, executed our code, and then—bam, it crashed.</p><p><strong>3. Who is the Real &quot;Culprit&quot;?</strong></p><p>Pay attention to this line in the Oops output:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU: 1 PID: 1699 Comm: insmod Tainted: G           OE     5.10.60-prod01 #6</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Here, the PID is 1699, and the process name is <code>insmod</code>.</p><p>If your instinct is &quot;Ah, the <code>insmod</code> process broke the kernel,&quot; then in this specific case, you are <strong>wrong</strong>.</p><p>Remember what we said in the previous chapter? In interrupt context, the <code>current</code> macro points to the <strong>unlucky victim</strong>—the process that happened to be running at that exact moment. It&#39;s just an innocent bystander that got &quot;face-slapped&quot; by our hard interrupt. Although the code was triggered by it (<code>insmod</code> caused the module to load, which in turn registered the <code>tasklet</code>), at the exact moment the crashing instruction executed, the CPU was actually working for the interrupt handler, not for <code>insmod</code>.</p><p>This also explains why sometimes the process you see in the Oops log is <code>swapper/0</code> (PID 0, the idle thread). The CPU was just idling when an interrupt suddenly yanked it up to do some work, but the work went poorly and crashed the CPU. <code>swapper/0</code> is purely taking the blame.</p><p><strong>4. Why Did the System Freeze?</strong></p><p>At the very end of the log, there&#39;s usually a prompt like this:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kernel panic - not syncing: Fatal exception in interrupt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This explains why your keyboard became completely unresponsive. The kernel realized—&quot;Oops, I crashed while handling an interrupt. This is an unrecoverable error. To ensure data safety, I&#39;d better end it all.&quot; So it triggered a panic, and the system stopped all scheduling.</p><hr><h3 id="wrapping-up-and-a-preview" tabindex="-1">Wrapping Up and a Preview <a class="header-anchor" href="#wrapping-up-and-a-preview" aria-label="Permalink to &quot;Wrapping Up and a Preview&quot;">​</a></h3><p>This method of &quot;exporting&quot; logs using a serial console is a required course for embedded developers and kernel engineers.</p><p>On physical machines, this concept evolves into a more flexible network tool—<strong>netconsole</strong>. It doesn&#39;t require a physical serial cable; instead, it broadcasts kernel logs via UDP packets to another machine on the local network.</p><p>In the next section, we&#39;ll migrate the battlefield from an x86 virtual machine to a real ARM device (a Raspberry Pi), to see what Oops looks like under a heterogeneous architecture and how to handle it using &quot;wireless debugging&quot; techniques like netconsole.</p>',17))])}const w=a(d,[["render",c]]);export{v as __pageData,w as default};
